mapper.select:
select * from nx_customer_referral_reward
where beneficiary_user_id = #{beneficiaryUserId}
  and trigger_user_id = #{triggerUserId}
  and rule_id = #{ruleId}
limit 1

mapper.update:
update nx_customer_referral_reward

    status = #{status},
    user_coupon_id = #{userCouponId},
    claimed_at = #{claimedAt}

where nx_customer_referral_reward_id = #{nxCustomerReferralRewardId}

mapper.select:
select count(*) from nx_customer_referral_reward


        and beneficiary_user_id = #{beneficiaryUserId}


        and status = #{status}

select rw.*, tu.nx_CU_user_id as trigger_nx_CU_user_id, tu.nx_CU_wx_nick_name as trigger_nx_CU_wx_nick_name, tu.nx_CU_wx_avatar_url as trigger_nx_CU_wx_avatar_url, tu.nx_CU_join_date as trigger_nx_CU_join_date, tpl.nx_community_coupon_id as tpl_nx_community_coupon_id, tpl.nx_community_coupon_name as tpl_nx_community_coupon_name, tpl.discount_amount as tpl_discount_amount, tpl.nx_cp_words as tpl_nx_cp_words, tpl.nx_cp_start_date as tpl_nx_cp_start_date, tpl.nx_cp_stop_date as tpl_nx_cp_stop_date, tpl.nx_cp_file_path as tpl_nx_cp_file_path, tpl.nx_cp_biz_purpose as tpl_nx_cp_biz_purpose, tpl.nx_cp_claim_strategy as tpl_nx_cp_claim_strategy from nx_customer_referral_reward rw left join nx_customer_user tu on tu.nx_CU_user_id = rw.trigger_user_id left join nx_community_coupon tpl on tpl.nx_community_coupon_id = rw.coupon_template_id
and rw.beneficiary_user_id = #{beneficiaryUserId}
and rw.trigger_user_id = #{triggerUserId}
and rw.status = #{status}
and rw.reward_level = #{rewardLevel}
order by rw.created_at desc
limit #{offset}, #{limit}

mapper.delete:
delete rw from nx_customer_referral_reward rw
inner join nx_customer_user_referral r on r.nx_customer_user_referral_id = rw.referral_id
where r.source_owner_type = #{sourceOwnerType}
  and r.source_owner_id = #{sourceOwnerId}
